class AnnotationRuleReproductionTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given an array annotation on the same line as the annotated construct`() {
        val code =
            """
            @[Suppress("DEPRECATION")] fun foo() {}
            """.trimIndent()
        val formattedCode =
            """
            @[Suppress("DEPRECATION")]
            fun foo() {}
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an array annotation with multiple entries on the same line as the annotated construct`() {
        val code =
            """
            @[Foo Bar] fun foo() {}
            """.trimIndent()
        val formattedCode =
            """
            @[Foo Bar]
            fun foo() {}
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }
}
"}

